### Swift Throws and Rethrows

Functions marked with `throws` can propagate errors to their caller. The `rethrows` keyword is used for functions that take throwing closures as parameters.

**Throwing Functions:**

```swift
// Function that can throw
func parseJSON(_ data: Data) throws -> [String: Any] {
    guard !data.isEmpty else {
        throw ParseError.emptyData
    }
    // Parsing logic
    return ["key": "value"]
}

// Calling a throwing function must be in do-catch or throwing context
func process(data: Data) throws {
    let json = try parseJSON(data)
    print(json)
}
```

**Throwing Initializers:**

```swift
struct User {
    let id: Int
    let name: String

    init?(json: [String: Any]) throws {
        guard let id = json["id"] as? Int else {
            throw ParseError.missingField("id")
        }
        guard let name = json["name"] as? String else {
            throw ParseError.missingField("name")
        }
        self.id = id
        self.name = name
    }
}
```

**Rethrows Keyword:**

```swift
// 'rethrows' means: this function throws only if its closure parameter throws
func map<T, U>(_ array: [T], transform: (T) throws -> U) rethrows -> [U] {
    var result: [U] = []
    for element in array {
        result.append(try transform(element))
    }
    return result
}

// Non-throwing closure - no try needed
let doubled = map([1, 2, 3]) { $0 * 2 }

// Throwing closure - must use try
let parsed = try map(["1", "2"]) { try Int($0)! }
```

**Thrown Error Propagation:**

```
Function A (throws) -- call --> Function B (throws)
    |                                |
    v                                v
  do-catch                        may throw
```

**Throwing Computed Properties and Subscripts:**

```swift
struct DataStore {
    private var data: [String: Any] = [:]

    // Throwing subscript
    subscript(key: String) -> Any {
        get throws {
            guard let value = data[key] else {
                throw StoreError.keyNotFound(key)
            }
            return value
        }
    }
}
```

> **Key Point:** Use `rethrows` for higher-order functions that accept throwing closures as parameters. This preserves flexibility for callers who may or may not use throwing closures.

A `rethrows` function can only throw if the function parameter it receives can throw. If the closure doesn't throw, no error handling is needed.

codeExample:
import Foundation

enum DataError: Error {
    case invalidFormat
    case missingField(String)
    case networkFailure
}

func fetchUserData(from url: String) throws -> [String: Any] {
    guard url.hasPrefix("https://") else {
        throw DataError.invalidFormat
    }
    guard url.contains("api") else {
        throw DataError.networkFailure
    }
    return ["name": "Alice", "age": 30]
}

// Rethrows example
func processItems<T, R>(_ items: [T], processor: (T) throws -> R) rethrows -> [R] {
    var results: [R] = []
    for item in items {
        results.append(try processor(item))
    }
    return results
}

// Non-throwing closure - no try needed
let numbers = [1, 2, 3]
let doubled = processItems(numbers) { $0 * 2 }
print("Doubled: \(doubled)")

// Throwing closure - must use do-catch or throwing context
let strings = ["1", "2", "abc"]
do {
    let parsed = try processItems(strings) { try Int($0) ?? { throw DataError.invalidFormat }() }
    print("Parsed: \(parsed)")
} catch {
    print("Error: \(error)")
}
